import React from "react";
import { useQuery } from "@tanstack/react-query";
import Loading from "../Pages/Loading/Loading";
import Navbar from "./Navbar/navbar";
import Footer from "./Footer/Footer";

function Layout({ children }) {
  // Fetch Home data
  const {
    data: homeData,
    isLoading: isLoadingHome,
    isSuccess: isSuccessHome,
    error: homeError,
  } = useQuery({
    queryKey: ["home"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/Home").then((res) => res.json()),
  });

  // Fetch Products data
  const {
    data: productsData,
    isLoading: isLoadingProducts,
    isSuccess: isSuccessProducts,
    error: productsError,
  } = useQuery({
    queryKey: ["products"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/AllProducts").then((res) => res.json()),
  });

  // Combined loading and error states
  const isLoading = isLoadingHome || isLoadingProducts;
  const error = homeError || productsError;

  if (isLoading) {
    return <Loading />;
  }

  if (error) {
    return <p>Error: {error.message}</p>;
  }

  return (
    <div>
      {/*<Navbar />*/}
      {/* Pass data and state as props to the children */}
      {React.cloneElement(children, {
        homeData,
        isSuccessHome,
        productsData,
        isSuccessProducts,
      })}
      <Footer />
    </div>
  );
}

export default Layout;

